import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import "./mentorDashboard.css";

const MentorDashboard = () => {
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState("overview");
  const [mentorData, setMentorData] = useState({});
  const [requests, setRequests] = useState([]);
  const [accepted, setAccepted] = useState([]);
  const [error, setError] = useState("");

  const mentor_id = 1; // ⚠️ Replace with dynamic ID later from token/localStorage

  const token = localStorage.getItem("token");

  useEffect(() => {
    fetchOverview();
    fetchRequests();
    fetchAccepted();
  }, []);

  const fetchOverview = async () => {
    try {
      const res = await fetch(`http://localhost:5050/api/mentor/overview/${mentor_id}`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      const data = await res.json();
      setMentorData(data);
    } catch {
      setError("Failed to load mentor overview");
    }
  };

  const fetchRequests = async () => {
    try {
      const res = await fetch(`http://localhost:5050/api/mentor/requests/${mentor_id}`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      const data = await res.json();
      setRequests(data);
    } catch {
      setError("Failed to load mentor requests");
    }
  };

  const fetchAccepted = async () => {
    try {
      const res = await fetch(`http://localhost:5050/api/mentor/accepted/${mentor_id}`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      const data = await res.json();
      setAccepted(data);
    } catch {
      setError("Failed to load accepted students");
    }
  };

  const handleLogout = () => {
    localStorage.clear();
    navigate("/login");
  };

  const handleDecision = async (id, status) => {
    await fetch(`http://localhost:5050/api/mentor/requests/update/${id}`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${token}`,
      },
      body: JSON.stringify({ status }),
    });
    fetchRequests();
    fetchAccepted();
  };

  return (
    <div className="mentor-dashboard">
      <div className="dashboard-header">
        <h1>Mentor Dashboard</h1>
        <button className="logout-btn" onClick={handleLogout}>Logout</button>
      </div>

      <div className="mentor-tabs">
        <button onClick={() => setActiveTab("overview")} className={activeTab === "overview" ? "active" : ""}>Overview</button>
        <button onClick={() => setActiveTab("requests")} className={activeTab === "requests" ? "active" : ""}>Requests</button>
        <button onClick={() => setActiveTab("accepted")} className={activeTab === "accepted" ? "active" : ""}>Accepted Students</button>
      </div>

      {error && <p className="error">{error}</p>}

      {/* 🏠 Overview */}
      {activeTab === "overview" && (
        <div className="overview-section">
          <h2>Welcome, {mentorData.facultyname}</h2>
          <p><strong>Specialization:</strong> {mentorData.specialization}</p>
          <p><strong>Slots:</strong> {mentorData.booked_slots || 0} booked / {mentorData.total_slots || 0} total</p>
        </div>
      )}

      {/* 📋 Requests */}
      {activeTab === "requests" && (
        <div className="requests-section">
          <h2>Pending Requests</h2>
          {requests.length === 0 ? (
            <p>No pending requests</p>
          ) : (
            requests.map((r) => (
              <div key={r.id} className="request-card">
                <h3>{r.project_title}</h3>
                <p><strong>Student:</strong> {r.studentname}</p>
                <p><strong>Domain:</strong> {r.domain}</p>
                <p>{r.description}</p>
                <button onClick={() => handleDecision(r.id, "accepted")} className="accept-btn">Accept</button>
                <button onClick={() => handleDecision(r.id, "rejected")} className="reject-btn">Reject</button>
              </div>
            ))
          )}
        </div>
      )}

      {/* 👩‍🎓 Accepted Students */}
      {activeTab === "accepted" && (
        <div className="accepted-section">
          <h2>Accepted Students</h2>
          {accepted.length === 0 ? (
            <p>No accepted students yet</p>
          ) : (
            accepted.map((a) => (
              <div key={a.id} className="accepted-card">
                <h3>{a.title}</h3>
                <p><strong>Student:</strong> {a.studentname}</p>
                <p><strong>Domain:</strong> {a.domain}</p>
                <p><strong>Status:</strong> {a.status}</p>
              </div>
            ))
          )}
        </div>
      )}
    </div>
  );
};

export default MentorDashboard;
